import{_ as a,o as i,c as t,a0 as n}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Create & Edit Plans","description":"","frontmatter":{},"headers":[],"relativePath":"admin/manage-plans.md","filePath":"admin/manage-plans.md"}'),o={name:"admin/manage-plans.md"};function s(r,e,l,p,c,d){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="create-edit-plans" tabindex="-1">Create &amp; Edit Plans <a class="header-anchor" href="#create-edit-plans" aria-label="Permalink to &quot;Create &amp; Edit Plans&quot;">​</a></h1><p>This guide is for <code>Supreme Admin</code> users only.</p><p>The plan editor controls what each subscription tier includes: scope, limits, features, and the pricing information shown in the app.</p><blockquote><p>Screenshot placeholder: <code>subs-plan-editor.png</code> (S62)</p></blockquote><h2 id="important-the-app-does-not-process-payments" tabindex="-1">Important: the app does not process payments <a class="header-anchor" href="#important-the-app-does-not-process-payments" aria-label="Permalink to &quot;Important: the app does not process payments&quot;">​</a></h2><p>The plan editor includes fields such as:</p><ul><li><strong>Price / month</strong></li><li><strong>Price / year</strong></li><li><strong>Currency</strong></li><li><strong>Payment provider</strong></li></ul><p>These are <strong>display fields only</strong>.</p><p>There is <strong>no automated payment processing</strong> inside the tracker. No checkout, no billing integration, and no automatic charging happens here. Payment is still handled manually through the request thread and support links. See <a href="./../subscriptions/payment-instructions.html">Payment Instructions &amp; Completing a Request</a>.</p><h2 id="what-you-can-edit-in-a-plan" tabindex="-1">What you can edit in a plan <a class="header-anchor" href="#what-you-can-edit-in-a-plan" aria-label="Permalink to &quot;What you can edit in a plan&quot;">​</a></h2><p>The plan editor lets you set:</p><ul><li>code</li><li>name</li><li>description</li><li>whether the plan applies to kingdoms, alliances, or both</li><li>premium features</li><li>default and active flags</li><li>display pricing fields</li><li>per-resource limits</li></ul><h2 id="applicability-warnings" tabindex="-1">Applicability warnings <a class="header-anchor" href="#applicability-warnings" aria-label="Permalink to &quot;Applicability warnings&quot;">​</a></h2><p>The editor validates whether your chosen features make sense for the plan scope.</p><p>For example:</p><ul><li>an alliance-only feature should not be attached to a kingdom-only plan without a reason</li><li>a kingdom-focused feature may not make sense on an alliance-only plan</li></ul><p>When you select an incompatible combination, the editor shows a warning. Treat that warning as real guidance, not decoration.</p><h2 id="features-and-coming-soon-items" tabindex="-1">Features and coming-soon items <a class="header-anchor" href="#features-and-coming-soon-items" aria-label="Permalink to &quot;Features and coming-soon items&quot;">​</a></h2><p>The feature picker shows both currently active features and coming-soon features. That means you can prepare a plan shape now even if some features are not live yet.</p><p>For feature meanings, see <a href="./../subscriptions/premium-features.html">Premium Features</a>.</p><h2 id="resource-limits" tabindex="-1">Resource limits <a class="header-anchor" href="#resource-limits" aria-label="Permalink to &quot;Resource limits&quot;">​</a></h2><p>Every plan also carries resource limits.</p><p>A few things to remember:</p><ul><li><code>0</code> means unlimited</li><li>limits are per resource type</li><li>some limits are what trigger warnings, cleanup pressure, and suspension behavior later</li></ul><p>For the user-side view of those limits, see <a href="./../subscriptions/overview.html">Subscriptions &amp; Quotas Explained</a>.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Keep plan codes stable and simple.</li><li>Use clear names so admins and requesters can tell plans apart.</li><li>Double-check applicability before saving.</li><li>Treat pricing as communication only, not billing logic.</li></ul>',27)])])}const m=a(o,[["render",s]]);export{u as __pageData,m as default};
